provider "aws" {
  region = "us-east-1"

  default_tags {
    tags = {
      Environment = "prod"
      ManagedBy   = "terraform"
      Team        = "platform"
      CostCenter  = "cc-1001"
    }
  }
}

resource "aws_instance" "web" {
  ami           = "ami-0abcdef1234567890"
  instance_type = "t3.medium"

  tags = {
    Name        = "web-server-01"
    Application = "web-frontend"
    # Environment, ManagedBy, Team, CostCenter inherited from default_tags
  }
}

# Create a Config rule requiring Environment and Team tags on EC2 and RDS
aws configservice put-config-rule   --config-rule '{
    "ConfigRuleName": "required-tags-ec2-rds",
    "Source": {
      "Owner": "AWS",
      "SourceIdentifier": "REQUIRED_TAGS"
    },
    "Scope": {
      "ComplianceResourceTypes": ["AWS::EC2::Instance", "AWS::RDS::DBInstance"]
    },
    "InputParameters": "{"tag1Key":"Environment","tag2Key":"Team","tag3Key":"CostCenter"}"
  }'   --region us-east-1

# List non-compliant resources
aws configservice get-compliance-details-by-config-rule   --config-rule-name required-tags-ec2-rds   --compliance-types NON_COMPLIANT   --region us-east-1
